        private bool compareFiles(string file1, string file2)
        {
        	Report.Info("Comparing " + file1 + " to ");
        	Report.Info("File 2: " + file2);
        	var file1Bytes = File.ReadAllBytes(file1);
        	var file2Bytes = File.ReadAllBytes(file2);
        	return ArraysEqual(file1Bytes, file2Bytes);
        }
        
        static bool ArraysEqual<T>(T[] a1, T[] a2)
        {
            if (ReferenceEquals(a1, a2))
            {
            	Report.Info("ReferenceEquals return TRUE");
                return true;
            }

            if (a1 == null || a2 == null)
            {
            	Report.Info("A1 or A2 is NULL, return FALSE");
                return false;
            }

            if (a1.Length != a2.Length)
            {
            	Report.Info("A1 Length: " + a1.Length.ToString() + " does not Equal A2 Length " + a2.Length.ToString() + ", return FALSE");
            	return false;
            }

            EqualityComparer<T> comparer = EqualityComparer<T>.Default;
            for (int i = 0; i < a1.Length; i++)
            {
                if (!comparer.Equals(a1[i], a2[i]))
                {
                	Report.Info("Element number " + i.ToString() + " of array 1 " + a1[i].ToString() + " DOES NOT EQUAL array 2 value " + a2[i].ToString() + " Returning FALSE");
                	return false;
                }
            }
            Report.Info("EqualityComparer returned TRUE");
            return true;
        }

