        public string MapDrive(string folder)
        {
        	try
            {
                var availableDrives = Enumerable.Range('D', 'Z' - 'D' + 1).Select(i => (Char)i + ":").Except(DriveInfo.GetDrives().Select(s => s.Name.Replace("\\", "")));
                var letter = availableDrives.First();
                string path = Path.Combine(Path.GetTempPath(), "MapDrive.bat");
                if (File.Exists(path))
                {
                    File.Delete(path);
                }

 

                using (var sw = new StreamWriter(path))
                {
                    sw.WriteLine("Echo y ");
                    sw.WriteLine("net use " + letter + " " + "\"" + folder + "\"" + " /persistent:no");
                }
                
                Report.Log(ReportLevel.Info, "UNC path successfully mapped to " + letter + " " + "\"" + folder + "\"");

 

                System.Threading.Thread.Sleep(2000);

 

                System.Diagnostics.Process.Start(path).WaitForExit();

 

                System.Threading.Thread.Sleep(2000);

 

                availableDrives = Enumerable.Range('D', 'Z' - 'D' + 1).Select(i => (Char)i + ":").Except(DriveInfo.GetDrives().Select(s => s.Name.Replace("\\", "")));
                if (availableDrives.Contains(letter))
                {
                	Report.Info("Drive Not Mapped!");
                }

 

               
                return letter;

 

            }
            catch (Exception)
            {
                return null;
            }
        
        }

        public void UnmapDrive(string driveLetter)
        {
             	string path = Path.Combine(Path.GetTempPath(), "UnMapDrive.bat");
                if (File.Exists(path))
                {
                    File.Delete(path);
                }

 

                using (var sw = new StreamWriter(path))
                {
                    sw.WriteLine("Echo y ");
                    sw.WriteLine("net use " + driveLetter + " " + "/d");
                }
                
             

 

                System.Threading.Thread.Sleep(2000);

 

                System.Diagnostics.Process.Start(path).WaitForExit();

 

                System.Threading.Thread.Sleep(2000);
                Report.Log(ReportLevel.Info, "Drive Letter: " + driveLetter + " has been disconnected");

        }
